#include <bits/stdc++.h>
using namespace std;
long long n,a[500005],ans;
void merge_sort(long long a[],long long l,long long r){
	if(r-l<=1)return;
	long long mid=(r+l>>1);
	merge_sort(a,l,mid);
	merge_sort(a,mid,r);
	long long i=l,j=mid,sum=l,t[n+1];
	while(sum<r){
		if(i>=mid || (a[j]<a[i] && j<r)){
			t[sum++]=a[j++];
			if(i<mid)ans+=mid-i;
		}else{
			t[sum++]=a[i++];
		}
	}
	for(long long i=l;i<r;i++)
		a[i]=t[i];
}
int main(){
	cin>>n;
	for(long long i=1;i<=n;i++)cin>>a[i];
	merge_sort(a,1,n+1);
	cout<<ans;
	return 0;
}
